/**
 * Module Loader Service Tests
 *
 * Unit tests for ModuleLoaderService covering:
 * - Module listing and filtering
 * - Module activation and deactivation
 * - Dependency checking
 * - Health checks
 * - Module discovery
 *
 * @module modules/_core/module-loader/__tests__/module-loader.service.spec
 */

import { describe, it, expect, beforeEach, vi, type Mock } from 'vitest';

import { ModuleLoaderService } from '@/modules/_core/module-loader/module-loader.service';
import { AppException } from '@/core/exceptions/app.exception';
import type { ModuleLoader, LoadedModule, ModuleCategory, ModuleStatus } from '@/core/kernel/module-loader';
import type { EventService } from '@/core/services/event.service';

// -----------------------------------------------------------------------------
// Mock Factories
// -----------------------------------------------------------------------------

/**
 * Creates a mock ModuleLoader (kernel)
 */
function createMockModuleLoader(): {
  getAllModules: Mock;
  getModule: Mock;
  getActiveModules: Mock;
  getCoreModules: Mock;
  getModulesByCategory: Mock;
  getModulesByStatus: Mock;
  getModuleDependents: Mock;
  resolveDependencies: Mock;
  activateModule: Mock;
  deactivateModule: Mock;
  isModuleActive: Mock;
  getStats: Mock;
  discoverModules: Mock;
  getAllPermissions: Mock;
  getAdminMenuItems: Mock;
} {
  return {
    getAllModules: vi.fn(),
    getModule: vi.fn(),
    getActiveModules: vi.fn(),
    getCoreModules: vi.fn(),
    getModulesByCategory: vi.fn(),
    getModulesByStatus: vi.fn(),
    getModuleDependents: vi.fn(),
    resolveDependencies: vi.fn(),
    activateModule: vi.fn(),
    deactivateModule: vi.fn(),
    isModuleActive: vi.fn(),
    getStats: vi.fn(),
    discoverModules: vi.fn(),
    getAllPermissions: vi.fn(),
    getAdminMenuItems: vi.fn(),
  };
}

/**
 * Creates a mock EventService
 */
function createMockEventService(): {
  emitCustom: Mock;
} {
  return {
    emitCustom: vi.fn(),
  };
}

/**
 * Creates a mock loaded module for testing
 */
function createMockLoadedModule(
  overrides: Partial<{
    id: string;
    name: string;
    displayName: string;
    version: string;
    description: string;
    author: string;
    category: ModuleCategory;
    status: ModuleStatus;
    core: boolean;
    enabled: boolean;
    priority: number;
    dependencies: { required: string[]; optional: string[] };
    permissions: string[];
    events: { emits: string[]; listens: string[] };
    admin: { menu?: { label: string; icon?: string; position: number } };
    loadedAt: Date;
    error?: string;
  }> = {}
): LoadedModule {
  const defaults = {
    id: 'test-module',
    name: 'test-module',
    displayName: 'Test Module',
    version: '1.0.0',
    description: 'A test module for testing',
    author: 'E-Menum',
    category: 'feature' as ModuleCategory,
    status: 'active' as ModuleStatus,
    core: false,
    enabled: true,
    priority: 100,
    dependencies: { required: [], optional: [] },
    permissions: ['test.view', 'test.create'],
    events: { emits: ['test.created'], listens: ['organization.created'] },
    admin: { menu: { label: 'Test', icon: 'ph-test', position: 50 } },
    loadedAt: new Date(),
    error: undefined,
  };

  const merged = { ...defaults, ...overrides };

  return {
    manifest: {
      id: merged.id,
      name: merged.name,
      displayName: merged.displayName,
      version: merged.version,
      description: merged.description,
      author: merged.author,
      category: merged.category,
      enabled: merged.enabled,
      priority: merged.priority,
      core: merged.core,
      dependencies: merged.dependencies,
      permissions: merged.permissions,
      routes: {},
      database: { migrations: false },
      hooks: {},
      admin: merged.admin,
      events: merged.events,
      planRestrictions: {},
    },
    path: `/src/modules/${merged.category}/${merged.id}`,
    status: merged.status,
    loadedAt: merged.loadedAt,
    error: merged.error,
  };
}

// -----------------------------------------------------------------------------
// Test Suite
// -----------------------------------------------------------------------------

describe('ModuleLoaderService', () => {
  let service: ModuleLoaderService;
  let mockModuleLoader: ReturnType<typeof createMockModuleLoader>;
  let mockEventService: ReturnType<typeof createMockEventService>;

  beforeEach(() => {
    mockModuleLoader = createMockModuleLoader();
    mockEventService = createMockEventService();

    service = new ModuleLoaderService(
      mockModuleLoader as unknown as ModuleLoader,
      mockEventService as unknown as EventService
    );
  });

  // ---------------------------------------------------------------------------
  // List Modules Tests
  // ---------------------------------------------------------------------------

  describe('listModules', () => {
    const mockModules = [
      createMockLoadedModule({ id: 'auth', displayName: 'Auth Module', category: 'core', core: true, priority: 10 }),
      createMockLoadedModule({ id: 'menu', displayName: 'Menu Module', category: 'feature', priority: 50 }),
      createMockLoadedModule({ id: 'ai-content', displayName: 'AI Content', category: 'ai', priority: 100 }),
    ];

    beforeEach(() => {
      mockModuleLoader.getAllModules.mockReturnValue(mockModules);
      mockModuleLoader.getModuleDependents.mockReturnValue([]);
      mockModuleLoader.getStats.mockReturnValue({
        total: 3,
        byStatus: { active: 3, discovered: 0, validated: 0, loaded: 0, disabled: 0, error: 0 },
        byCategory: { core: 1, feature: 1, ai: 1, integration: 0, example: 0, stub: 0 },
      });
    });

    it('should return all modules with stats', async () => {
      // Act
      const result = await service.listModules();

      // Assert
      expect(result.modules).toHaveLength(3);
      expect(result.stats.total).toBe(3);
      expect(mockModuleLoader.getAllModules).toHaveBeenCalled();
    });

    it('should filter by category', async () => {
      // Act
      const result = await service.listModules({ category: 'core' });

      // Assert
      expect(result.modules).toHaveLength(1);
      expect(result.modules[0]?.id).toBe('auth');
    });

    it('should filter by status', async () => {
      // Arrange
      const modulesWithDisabled = [
        ...mockModules,
        createMockLoadedModule({ id: 'disabled-mod', status: 'disabled' }),
      ];
      mockModuleLoader.getAllModules.mockReturnValue(modulesWithDisabled);

      // Act
      const result = await service.listModules({ status: 'active' });

      // Assert
      expect(result.modules).toHaveLength(3);
      expect(result.modules.every((m) => m.status === 'active')).toBe(true);
    });

    it('should filter by isCore', async () => {
      // Act
      const result = await service.listModules({ isCore: true });

      // Assert
      expect(result.modules).toHaveLength(1);
      expect(result.modules[0]?.isCore).toBe(true);
    });

    it('should filter by isEnabled', async () => {
      // Arrange
      const modulesWithDisabled = [
        ...mockModules,
        createMockLoadedModule({ id: 'disabled-mod', status: 'disabled' }),
      ];
      mockModuleLoader.getAllModules.mockReturnValue(modulesWithDisabled);

      // Act
      const result = await service.listModules({ isEnabled: true });

      // Assert
      expect(result.modules.every((m) => m.status === 'active')).toBe(true);
    });

    it('should search by name', async () => {
      // Act
      const result = await service.listModules({ search: 'Menu' });

      // Assert
      expect(result.modules).toHaveLength(1);
      expect(result.modules[0]?.displayName).toBe('Menu Module');
    });

    it('should search by description', async () => {
      // Act
      const result = await service.listModules({ search: 'test' });

      // Assert
      expect(result.modules.length).toBeGreaterThan(0);
    });

    it('should sort by priority (default)', async () => {
      // Act
      const result = await service.listModules();

      // Assert
      expect(result.modules[0]?.id).toBe('auth'); // priority: 10
      expect(result.modules[1]?.id).toBe('menu'); // priority: 50
      expect(result.modules[2]?.id).toBe('ai-content'); // priority: 100
    });

    it('should sort by name', async () => {
      // Act
      const result = await service.listModules({ sortBy: 'name' });

      // Assert
      expect(result.modules[0]?.displayName).toBe('AI Content');
      expect(result.modules[1]?.displayName).toBe('Auth Module');
      expect(result.modules[2]?.displayName).toBe('Menu Module');
    });

    it('should sort in descending order', async () => {
      // Act
      const result = await service.listModules({ sortBy: 'priority', sortOrder: 'desc' });

      // Assert
      expect(result.modules[0]?.id).toBe('ai-content'); // priority: 100
      expect(result.modules[2]?.id).toBe('auth'); // priority: 10
    });
  });

  // ---------------------------------------------------------------------------
  // Get Module By ID Tests
  // ---------------------------------------------------------------------------

  describe('getModuleById', () => {
    it('should return module when found', async () => {
      // Arrange
      const mockModule = createMockLoadedModule({ id: 'menu' });
      mockModuleLoader.getModule.mockReturnValue(mockModule);
      mockModuleLoader.getModuleDependents.mockReturnValue([]);

      // Act
      const result = await service.getModuleById('menu');

      // Assert
      expect(result).not.toBeNull();
      expect(result?.id).toBe('menu');
      expect(mockModuleLoader.getModule).toHaveBeenCalledWith('menu');
    });

    it('should return null when module not found', async () => {
      // Arrange
      mockModuleLoader.getModule.mockReturnValue(undefined);

      // Act
      const result = await service.getModuleById('nonexistent');

      // Assert
      expect(result).toBeNull();
    });

    it('should include dependents in module info', async () => {
      // Arrange
      const mockModule = createMockLoadedModule({ id: 'auth' });
      mockModuleLoader.getModule.mockReturnValue(mockModule);
      mockModuleLoader.getModuleDependents.mockReturnValue(['menu', 'orders']);

      // Act
      const result = await service.getModuleById('auth');

      // Assert
      expect(result?.dependents).toEqual(['menu', 'orders']);
    });
  });

  describe('getModuleByIdOrThrow', () => {
    it('should return module when found', async () => {
      // Arrange
      const mockModule = createMockLoadedModule({ id: 'menu' });
      mockModuleLoader.getModule.mockReturnValue(mockModule);
      mockModuleLoader.getModuleDependents.mockReturnValue([]);

      // Act
      const result = await service.getModuleByIdOrThrow('menu');

      // Assert
      expect(result.id).toBe('menu');
    });

    it('should throw AppException when module not found', async () => {
      // Arrange
      mockModuleLoader.getModule.mockReturnValue(undefined);

      // Act & Assert
      await expect(service.getModuleByIdOrThrow('nonexistent')).rejects.toThrow(AppException);
    });
  });

  // ---------------------------------------------------------------------------
  // Get Active/Core/Category Modules Tests
  // ---------------------------------------------------------------------------

  describe('getActiveModules', () => {
    it('should return only active modules', async () => {
      // Arrange
      const activeModules = [
        createMockLoadedModule({ id: 'auth', status: 'active' }),
        createMockLoadedModule({ id: 'menu', status: 'active' }),
      ];
      mockModuleLoader.getActiveModules.mockReturnValue(activeModules);
      mockModuleLoader.getModuleDependents.mockReturnValue([]);

      // Act
      const result = await service.getActiveModules();

      // Assert
      expect(result).toHaveLength(2);
      expect(result.every((m) => m.status === 'active')).toBe(true);
    });
  });

  describe('getCoreModules', () => {
    it('should return only core modules', async () => {
      // Arrange
      const coreModules = [
        createMockLoadedModule({ id: 'auth', core: true }),
        createMockLoadedModule({ id: 'users', core: true }),
      ];
      mockModuleLoader.getCoreModules.mockReturnValue(coreModules);
      mockModuleLoader.getModuleDependents.mockReturnValue([]);

      // Act
      const result = await service.getCoreModules();

      // Assert
      expect(result).toHaveLength(2);
      expect(result.every((m) => m.isCore)).toBe(true);
    });
  });

  describe('getModulesByCategory', () => {
    it('should return modules by category', async () => {
      // Arrange
      const aiModules = [
        createMockLoadedModule({ id: 'ai-content', category: 'ai' }),
        createMockLoadedModule({ id: 'ai-analytics', category: 'ai' }),
      ];
      mockModuleLoader.getModulesByCategory.mockReturnValue(aiModules);
      mockModuleLoader.getModuleDependents.mockReturnValue([]);

      // Act
      const result = await service.getModulesByCategory('ai');

      // Assert
      expect(result).toHaveLength(2);
      expect(result.every((m) => m.category === 'ai')).toBe(true);
      expect(mockModuleLoader.getModulesByCategory).toHaveBeenCalledWith('ai');
    });
  });

  describe('getModulesByStatus', () => {
    it('should return modules by status', async () => {
      // Arrange
      const errorModules = [createMockLoadedModule({ id: 'broken-mod', status: 'error', error: 'Load failed' })];
      mockModuleLoader.getModulesByStatus.mockReturnValue(errorModules);
      mockModuleLoader.getModuleDependents.mockReturnValue([]);

      // Act
      const result = await service.getModulesByStatus('error');

      // Assert
      expect(result).toHaveLength(1);
      expect(result[0]?.status).toBe('error');
      expect(mockModuleLoader.getModulesByStatus).toHaveBeenCalledWith('error');
    });
  });

  // ---------------------------------------------------------------------------
  // Stats Tests
  // ---------------------------------------------------------------------------

  describe('getStats', () => {
    it('should return module statistics', () => {
      // Arrange
      const mockStats = {
        total: 10,
        byStatus: { active: 8, disabled: 1, error: 1, discovered: 0, validated: 0, loaded: 0 },
        byCategory: { core: 3, feature: 5, ai: 2, integration: 0, example: 0, stub: 0 },
      };
      mockModuleLoader.getStats.mockReturnValue(mockStats);
      mockModuleLoader.getAllModules.mockReturnValue([
        createMockLoadedModule({ core: true }),
        createMockLoadedModule({ core: true }),
        createMockLoadedModule({ core: true }),
      ]);

      // Act
      const result = service.getStats();

      // Assert
      expect(result.total).toBe(10);
      expect(result.active).toBe(8);
      expect(result.core).toBe(3);
      expect(result.errors).toBe(1);
    });
  });

  // ---------------------------------------------------------------------------
  // Activate Module Tests
  // ---------------------------------------------------------------------------

  describe('activateModule', () => {
    it('should activate module successfully', async () => {
      // Arrange
      const mockModule = createMockLoadedModule({ id: 'menu', status: 'disabled' });
      const activatedModule = createMockLoadedModule({ id: 'menu', status: 'active' });

      mockModuleLoader.getModule.mockReturnValueOnce(mockModule).mockReturnValueOnce(activatedModule);
      mockModuleLoader.resolveDependencies.mockReturnValue({
        resolved: true,
        missing: [],
        circular: [],
        loadOrder: ['menu'],
      });
      mockModuleLoader.activateModule.mockResolvedValue(true);
      mockModuleLoader.getModuleDependents.mockReturnValue([]);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.activateModule({ moduleId: 'menu' });

      // Assert
      expect(result.success).toBe(true);
      expect(result.module?.status).toBe('active');
      expect(result.message).toContain('activated');
      expect(mockModuleLoader.activateModule).toHaveBeenCalledWith('menu');
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'module.activated',
        expect.objectContaining({ moduleId: 'menu' })
      );
    });

    it('should return success when module is already active', async () => {
      // Arrange
      const mockModule = createMockLoadedModule({ id: 'menu', status: 'active' });
      mockModuleLoader.getModule.mockReturnValue(mockModule);
      mockModuleLoader.getModuleDependents.mockReturnValue([]);

      // Act
      const result = await service.activateModule({ moduleId: 'menu' });

      // Assert
      expect(result.success).toBe(true);
      expect(result.message).toContain('already active');
      expect(mockModuleLoader.activateModule).not.toHaveBeenCalled();
    });

    it('should throw error when module not found', async () => {
      // Arrange
      mockModuleLoader.getModule.mockReturnValue(undefined);

      // Act & Assert
      await expect(service.activateModule({ moduleId: 'nonexistent' })).rejects.toThrow(AppException);
    });

    it('should throw error when dependencies are missing', async () => {
      // Arrange
      const mockModule = createMockLoadedModule({ id: 'menu', status: 'disabled' });
      mockModuleLoader.getModule.mockReturnValue(mockModule);
      mockModuleLoader.resolveDependencies.mockReturnValue({
        resolved: false,
        missing: ['auth', 'users'],
        circular: [],
        loadOrder: [],
      });

      // Act & Assert
      await expect(service.activateModule({ moduleId: 'menu' })).rejects.toThrow(AppException);
    });

    it('should throw error when circular dependencies detected', async () => {
      // Arrange
      const mockModule = createMockLoadedModule({ id: 'menu', status: 'disabled' });
      mockModuleLoader.getModule.mockReturnValue(mockModule);
      mockModuleLoader.resolveDependencies.mockReturnValue({
        resolved: false,
        missing: [],
        circular: ['menu', 'orders'],
        loadOrder: [],
      });

      // Act & Assert
      await expect(service.activateModule({ moduleId: 'menu' })).rejects.toThrow(AppException);
    });

    it('should skip dependency check when force is true', async () => {
      // Arrange
      const mockModule = createMockLoadedModule({ id: 'menu', status: 'disabled' });
      const activatedModule = createMockLoadedModule({ id: 'menu', status: 'active' });

      mockModuleLoader.getModule.mockReturnValueOnce(mockModule).mockReturnValueOnce(activatedModule);
      mockModuleLoader.activateModule.mockResolvedValue(true);
      mockModuleLoader.getModuleDependents.mockReturnValue([]);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.activateModule({ moduleId: 'menu', force: true });

      // Assert
      expect(result.success).toBe(true);
      expect(mockModuleLoader.resolveDependencies).not.toHaveBeenCalled();
    });

    it('should throw error when activation fails', async () => {
      // Arrange
      const mockModule = createMockLoadedModule({ id: 'menu', status: 'disabled' });
      const errorModule = createMockLoadedModule({ id: 'menu', status: 'error', error: 'Activation failed' });

      mockModuleLoader.getModule.mockReturnValueOnce(mockModule).mockReturnValueOnce(errorModule);
      mockModuleLoader.resolveDependencies.mockReturnValue({
        resolved: true,
        missing: [],
        circular: [],
        loadOrder: ['menu'],
      });
      mockModuleLoader.activateModule.mockResolvedValue(false);

      // Act & Assert
      await expect(service.activateModule({ moduleId: 'menu' })).rejects.toThrow(AppException);
    });
  });

  // ---------------------------------------------------------------------------
  // Deactivate Module Tests
  // ---------------------------------------------------------------------------

  describe('deactivateModule', () => {
    it('should deactivate module successfully', async () => {
      // Arrange
      const mockModule = createMockLoadedModule({ id: 'menu', status: 'active', core: false });
      const deactivatedModule = createMockLoadedModule({ id: 'menu', status: 'disabled', core: false });

      mockModuleLoader.getModule.mockReturnValueOnce(mockModule).mockReturnValueOnce(deactivatedModule);
      mockModuleLoader.getModuleDependents.mockReturnValue([]);
      mockModuleLoader.deactivateModule.mockResolvedValue(true);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.deactivateModule({ moduleId: 'menu' });

      // Assert
      expect(result.success).toBe(true);
      expect(result.module?.status).toBe('disabled');
      expect(result.message).toContain('deactivated');
      expect(mockModuleLoader.deactivateModule).toHaveBeenCalledWith('menu');
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'module.deactivated',
        expect.objectContaining({ moduleId: 'menu' })
      );
    });

    it('should return success when module is already inactive', async () => {
      // Arrange
      const mockModule = createMockLoadedModule({ id: 'menu', status: 'disabled', core: false });
      mockModuleLoader.getModule.mockReturnValue(mockModule);
      mockModuleLoader.getModuleDependents.mockReturnValue([]);

      // Act
      const result = await service.deactivateModule({ moduleId: 'menu' });

      // Assert
      expect(result.success).toBe(true);
      expect(result.message).toContain('already inactive');
      expect(mockModuleLoader.deactivateModule).not.toHaveBeenCalled();
    });

    it('should throw error when module not found', async () => {
      // Arrange
      mockModuleLoader.getModule.mockReturnValue(undefined);

      // Act & Assert
      await expect(service.deactivateModule({ moduleId: 'nonexistent' })).rejects.toThrow(AppException);
    });

    it('should throw error when trying to deactivate core module', async () => {
      // Arrange
      const coreModule = createMockLoadedModule({ id: 'auth', core: true, status: 'active' });
      mockModuleLoader.getModule.mockReturnValue(coreModule);

      // Act & Assert
      await expect(service.deactivateModule({ moduleId: 'auth' })).rejects.toThrow(AppException);
    });

    it('should throw error when active modules depend on it', async () => {
      // Arrange
      const mockModule = createMockLoadedModule({ id: 'auth', status: 'active', core: false });
      mockModuleLoader.getModule.mockImplementation((id) => {
        if (id === 'auth') return mockModule;
        return createMockLoadedModule({ id, status: 'active' });
      });
      mockModuleLoader.getModuleDependents.mockReturnValue(['menu', 'orders']);

      // Act & Assert
      await expect(service.deactivateModule({ moduleId: 'auth' })).rejects.toThrow(AppException);
    });

    it('should force deactivate with warnings when dependents exist', async () => {
      // Arrange
      const mockModule = createMockLoadedModule({ id: 'auth', status: 'active', core: false });
      const deactivatedModule = createMockLoadedModule({ id: 'auth', status: 'disabled', core: false });

      mockModuleLoader.getModule
        .mockReturnValueOnce(mockModule)
        .mockImplementation((id) => {
          if (id === 'auth') return deactivatedModule;
          return createMockLoadedModule({ id, status: 'active' });
        });
      mockModuleLoader.getModuleDependents.mockReturnValue(['menu']);
      mockModuleLoader.deactivateModule.mockResolvedValue(true);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.deactivateModule({ moduleId: 'auth', force: true });

      // Assert
      expect(result.success).toBe(true);
      expect(result.warnings).toBeDefined();
      expect(result.warnings?.length).toBeGreaterThan(0);
    });

    it('should throw error when deactivation fails', async () => {
      // Arrange
      const mockModule = createMockLoadedModule({ id: 'menu', status: 'active', core: false });
      const errorModule = createMockLoadedModule({ id: 'menu', status: 'error', error: 'Deactivation failed' });

      mockModuleLoader.getModule.mockReturnValueOnce(mockModule).mockReturnValueOnce(errorModule);
      mockModuleLoader.getModuleDependents.mockReturnValue([]);
      mockModuleLoader.deactivateModule.mockResolvedValue(false);

      // Act & Assert
      await expect(service.deactivateModule({ moduleId: 'menu' })).rejects.toThrow(AppException);
    });
  });

  // ---------------------------------------------------------------------------
  // Dependency Check Tests
  // ---------------------------------------------------------------------------

  describe('checkDependencies', () => {
    it('should return valid result when all dependencies are satisfied', () => {
      // Arrange
      mockModuleLoader.resolveDependencies.mockReturnValue({
        resolved: true,
        loadOrder: ['auth', 'users', 'menu'],
        missing: [],
        circular: [],
      });
      mockModuleLoader.getModule.mockReturnValue(
        createMockLoadedModule({
          id: 'menu',
          dependencies: { required: ['auth'], optional: ['analytics'] },
        })
      );

      // Act
      const result = service.checkDependencies('menu');

      // Assert
      expect(result.valid).toBe(true);
      expect(result.missing).toHaveLength(0);
      expect(result.circular).toHaveLength(0);
      expect(result.loadOrder).toEqual(['auth', 'users', 'menu']);
    });

    it('should return missing dependencies', () => {
      // Arrange
      mockModuleLoader.resolveDependencies.mockReturnValue({
        resolved: false,
        loadOrder: [],
        missing: ['auth', 'users'],
        circular: [],
      });
      mockModuleLoader.getModule.mockReturnValue(undefined);

      // Act
      const result = service.checkDependencies('menu');

      // Assert
      expect(result.valid).toBe(false);
      expect(result.missing).toEqual(['auth', 'users']);
    });

    it('should return circular dependencies', () => {
      // Arrange
      mockModuleLoader.resolveDependencies.mockReturnValue({
        resolved: false,
        loadOrder: [],
        missing: [],
        circular: ['menu', 'orders'],
      });
      mockModuleLoader.getModule.mockReturnValue(undefined);

      // Act
      const result = service.checkDependencies('menu');

      // Assert
      expect(result.valid).toBe(false);
      expect(result.circular).toEqual(['menu', 'orders']);
    });

    it('should return available optional dependencies', () => {
      // Arrange
      mockModuleLoader.resolveDependencies.mockReturnValue({
        resolved: true,
        loadOrder: ['auth', 'menu'],
        missing: [],
        circular: [],
      });
      mockModuleLoader.getModule.mockImplementation((id) => {
        if (id === 'menu') {
          return createMockLoadedModule({
            id: 'menu',
            dependencies: { required: ['auth'], optional: ['analytics'] },
          });
        }
        if (id === 'analytics') {
          return createMockLoadedModule({ id: 'analytics', status: 'active' });
        }
        return undefined;
      });

      // Act
      const result = service.checkDependencies('menu');

      // Assert
      expect(result.availableOptional).toContain('analytics');
    });

    it('should check all modules when no moduleId provided', () => {
      // Arrange
      mockModuleLoader.resolveDependencies.mockReturnValue({
        resolved: true,
        loadOrder: ['auth', 'users', 'menu'],
        missing: [],
        circular: [],
      });

      // Act
      const result = service.checkDependencies();

      // Assert
      expect(mockModuleLoader.resolveDependencies).toHaveBeenCalledWith(undefined);
      expect(result.valid).toBe(true);
    });
  });

  describe('getModuleDependents', () => {
    it('should return module dependents', () => {
      // Arrange
      mockModuleLoader.getModuleDependents.mockReturnValue(['menu', 'orders', 'analytics']);

      // Act
      const result = service.getModuleDependents('auth');

      // Assert
      expect(result).toEqual(['menu', 'orders', 'analytics']);
      expect(mockModuleLoader.getModuleDependents).toHaveBeenCalledWith('auth');
