  describe('checkModuleHealth', () => {
    it('should return healthy status for active module', async () => {
      // Arrange
      const mockModule = createMockLoadedModule({ id: 'menu', status: 'active', version: '1.0.0' });
      mockModuleLoader.getModule.mockReturnValue(mockModule);
      mockModuleLoader.resolveDependencies.mockReturnValue({
        resolved: true,
        loadOrder: ['menu'],
        missing: [],
        circular: [],
      });

      // Act
      const result = await service.checkModuleHealth('menu');

      // Assert
      expect(result.moduleId).toBe('menu');
      expect(result.status).toBe('healthy');
      expect(result.message).toContain('healthy');
      expect(result.details?.version).toBe('1.0.0');
      expect(result.checkedAt).toBeInstanceOf(Date);
    });

    it('should return unhealthy status when module not found', async () => {
      // Arrange
      mockModuleLoader.getModule.mockReturnValue(undefined);

      // Act
      const result = await service.checkModuleHealth('nonexistent');

      // Assert
      expect(result.status).toBe('unhealthy');
      expect(result.message).toContain('not found');
    });

    it('should return unhealthy status when module has error', async () => {
      // Arrange
      const errorModule = createMockLoadedModule({
        id: 'broken',
        status: 'error',
        error: 'Failed to load',
      });
      mockModuleLoader.getModule.mockReturnValue(errorModule);

      // Act
      const result = await service.checkModuleHealth('broken');

      // Assert
      expect(result.status).toBe('unhealthy');
      expect(result.details?.error).toBe('Failed to load');
    });

    it('should return degraded status when module is not active', async () => {
      // Arrange
      const disabledModule = createMockLoadedModule({ id: 'disabled', status: 'disabled' });
      mockModuleLoader.getModule.mockReturnValue(disabledModule);

      // Act
      const result = await service.checkModuleHealth('disabled');

      // Assert
      expect(result.status).toBe('degraded');
      expect(result.details?.status).toBe('disabled');
    });

    it('should return degraded status when dependencies not satisfied', async () => {
      // Arrange
      const mockModule = createMockLoadedModule({ id: 'menu', status: 'active' });
      mockModuleLoader.getModule.mockReturnValue(mockModule);
      mockModuleLoader.resolveDependencies.mockReturnValue({
        resolved: false,
        loadOrder: [],
        missing: ['auth'],
        circular: [],
      });

      // Act
      const result = await service.checkModuleHealth('menu');

      // Assert
      expect(result.status).toBe('degraded');
      expect(result.details?.missing).toContain('auth');
    });
  });

